import{_ as t,o as a,c as l,a4 as i}from"./chunks/framework.Bz0lZ1uX.js";const b=JSON.parse('{"title":"搜索与筛选指南","description":"","frontmatter":{},"headers":[],"relativePath":"guide/搜索筛选.md","filePath":"guide/搜索筛选.md","lastUpdated":null}'),o={name:"guide/搜索筛选.md"},e=i('<h1 id="搜索与筛选指南" tabindex="-1">搜索与筛选指南 <a class="header-anchor" href="#搜索与筛选指南" aria-label="Permalink to &quot;搜索与筛选指南&quot;">​</a></h1><p>本指南介绍如何高效使用素材库的搜索与筛选功能，快速找到所需素材。</p><h2 id="搜索功能" tabindex="-1">搜索功能 <a class="header-anchor" href="#搜索功能" aria-label="Permalink to &quot;搜索功能&quot;">​</a></h2><h3 id="基础搜索" tabindex="-1">基础搜索 <a class="header-anchor" href="#基础搜索" aria-label="Permalink to &quot;基础搜索&quot;">​</a></h3><p><strong>方法</strong>: 使用页面顶部的搜索框</p><p><strong>搜索范围</strong>:</p><ul><li>素材标题</li><li>素材内容</li><li>标签</li><li>适用主题</li></ul><p><strong>示例</strong>:</p><ul><li>搜索&quot;袁隆平&quot; → 找到袁隆平相关素材</li><li>搜索&quot;创新&quot; → 找到所有包含&quot;创新&quot;的素材</li><li>搜索&quot;#科学家&quot; → 找到所有标记为科学家的素材</li></ul><h3 id="高级搜索技巧" tabindex="-1">高级搜索技巧 <a class="header-anchor" href="#高级搜索技巧" aria-label="Permalink to &quot;高级搜索技巧&quot;">​</a></h3><h4 id="_1-精确搜索" tabindex="-1">1. 精确搜索 <a class="header-anchor" href="#_1-精确搜索" aria-label="Permalink to &quot;1. 精确搜索&quot;">​</a></h4><p>使用引号进行精确匹配：</p><ul><li><code>&quot;延迟满足&quot;</code> → 精确匹配该词组</li></ul><h4 id="_2-多关键词搜索" tabindex="-1">2. 多关键词搜索 <a class="header-anchor" href="#_2-多关键词搜索" aria-label="Permalink to &quot;2. 多关键词搜索&quot;">​</a></h4><p>使用空格分隔多个关键词：</p><ul><li><code>科学家 坚持</code> → 包含两个关键词的素材</li><li><code>历史 智慧 谋略</code> → 同时包含三个关键词</li></ul><h4 id="_3-排除搜索" tabindex="-1">3. 排除搜索 <a class="header-anchor" href="#_3-排除搜索" aria-label="Permalink to &quot;3. 排除搜索&quot;">​</a></h4><p>使用减号排除特定内容：</p><ul><li><code>人物 -体育</code> → 非体育类人物</li><li><code>事件 -教育</code> → 非教育类事件</li></ul><h4 id="_4-标签搜索" tabindex="-1">4. 标签搜索 <a class="header-anchor" href="#_4-标签搜索" aria-label="Permalink to &quot;4. 标签搜索&quot;">​</a></h4><p>直接搜索标签：</p><ul><li><code>#勤奋</code> → 所有标记为勤奋的素材</li><li><code>#科技创新</code> → 所有科技创新相关素材</li></ul><h2 id="筛选功能" tabindex="-1">筛选功能 <a class="header-anchor" href="#筛选功能" aria-label="Permalink to &quot;筛选功能&quot;">​</a></h2><h3 id="按分类筛选" tabindex="-1">按分类筛选 <a class="header-anchor" href="#按分类筛选" aria-label="Permalink to &quot;按分类筛选&quot;">​</a></h3><p>通过左侧导航栏选择素材分类：</p><ul><li>📚 人物素材</li><li>📰 事件素材</li><li>💬 名言警句</li><li>📜 历史典故</li><li>🔬 科学研究</li><li>🌐 社会热点</li></ul><h3 id="按主题筛选" tabindex="-1">按主题筛选 <a class="header-anchor" href="#按主题筛选" aria-label="Permalink to &quot;按主题筛选&quot;">​</a></h3><p>在每个分类页面，可以通过以下方式筛选：</p><p><strong>主题类别</strong>:</p><ul><li>人物品格（勤奋、坚持、奉献、创新等）</li><li>社会价值（责任、合作、公平、正义等）</li><li>教育成长（学习、梦想、挫折、成长等）</li><li>科技时代（创新、AI、数字化等）</li><li>文化传承（文化自信、传统、非遗等）</li></ul><p><strong>适用场景</strong>:</p><ul><li>开头引入素材</li><li>论点支撑素材</li><li>对比论证素材</li><li>结尾升华素材</li></ul><h3 id="按标签筛选" tabindex="-1">按标签筛选 <a class="header-anchor" href="#按标签筛选" aria-label="Permalink to &quot;按标签筛选&quot;">​</a></h3><p>每个素材都标注了标签，可通过标签快速筛选：</p><ol><li><strong>点击标签</strong>: 点击素材页面上的标签，查看同类素材</li><li><strong>组合标签</strong>: 结合多个标签精准定位</li><li><strong>标签云</strong>: 查看热门标签，快速选择</li></ol><h2 id="实用搜索场景" tabindex="-1">实用搜索场景 <a class="header-anchor" href="#实用搜索场景" aria-label="Permalink to &quot;实用搜索场景&quot;">​</a></h2><h3 id="场景一-写-创新-主题作文" tabindex="-1">场景一：写&quot;创新&quot;主题作文 <a class="header-anchor" href="#场景一-写-创新-主题作文" aria-label="Permalink to &quot;场景一：写&quot;创新&quot;主题作文&quot;">​</a></h3><p><strong>步骤</strong>:</p><ol><li>搜索&quot;创新&quot;</li><li>筛选#人物素材中的创新人物（任正非、屠呦呦）</li><li>筛选#科学研究中的创新案例（量子通信、CRISPR）</li><li>筛选#名言警句中的创新名言（&quot;苟日新，日日新&quot;）</li><li>筛选#社会热点中的创新话题（AI发展）</li></ol><h3 id="场景二-写-坚持-主题作文" tabindex="-1">场景二：写&quot;坚持&quot;主题作文 <a class="header-anchor" href="#场景二-写-坚持-主题作文" aria-label="Permalink to &quot;场景二：写&quot;坚持&quot;主题作文&quot;">​</a></h3><p><strong>步骤</strong>:</p><ol><li>搜索&quot;坚持&quot;</li><li>查找人物素材（苏炳添、袁隆平）</li><li>查找历史典故（卧薪尝胆、凿壁偷光）</li><li>查找名言警句（&quot;锲而不舍，金石可镂&quot;）</li><li>查找科学研究（1万小时定律）</li></ol><h3 id="场景三-写-责任-主题作文" tabindex="-1">场景三：写&quot;责任&quot;主题作文 <a class="header-anchor" href="#场景三-写-责任-主题作文" aria-label="Permalink to &quot;场景三：写&quot;责任&quot;主题作文&quot;">​</a></h3><p><strong>步骤</strong>:</p><ol><li>搜索&quot;责任&quot;</li><li>查找人物素材（樊锦诗、曹德旺）</li><li>查找事件素材（脱贫攻坚、河南暴雨救援）</li><li>查找名言警句（&quot;天下兴亡，匹夫有责&quot;）</li><li>查找社会热点（网络文明、志愿服务）</li></ol><h2 id="搜索效率提升技巧" tabindex="-1">搜索效率提升技巧 <a class="header-anchor" href="#搜索效率提升技巧" aria-label="Permalink to &quot;搜索效率提升技巧&quot;">​</a></h2><table><thead><tr><th>技巧</th><th>说明</th><th>效果</th></tr></thead><tbody><tr><td>使用标签</td><td>优先用标签搜索</td><td>精准定位</td></tr><tr><td>组合关键词</td><td>2-3个关键词组合</td><td>缩小范围</td></tr><tr><td>分类限定</td><td>先在分类中再搜索</td><td>提高效率</td></tr><tr><td>收藏常用</td><td>收藏高频使用素材</td><td>快速调用</td></tr><tr><td>关注更新</td><td>定期查看新增素材</td><td>获取最新内容</td></tr></tbody></table><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 搜索不到想要的素材？</strong> A: 尝试更换关键词，或使用标签搜索。</p><p><strong>Q: 搜索结果太多？</strong> A: 增加关键词或使用多标签组合筛选。</p><p><strong>Q: 如何找到最新素材？</strong> A: 查看各分类页面的最新更新，关注新增内容。</p><p><strong>Q: 能否自定义搜索条件？</strong> A: 目前支持关键词、标签、分类筛选，后续将增加更多筛选维度。</p>',52),r=[e];function d(h,n,u,s,q,c){return a(),l("div",null,r)}const _=t(o,[["render",d]]);export{b as __pageData,_ as default};
